3	// Atributos de fragmentos recebidos como entrada ("in") pelo Fragment Shader.
4	// Neste exemplo, este atributo foi gerado pelo rasterizador como a
5	// interpolação da posição global e a normal de cada vértice, definidas em
6	// "shader_vertex.glsl" e "main.cpp".
7	in vec4 position_world;
