99	
100	// Luzes direcionais configuradas diretamente no shader.
101	// --- LUZES DA SALA 1 (Point Lights) ---
102	const int LIGHT_COUNT = 4; // 4 cantos da sala 1R
103	const vec3 LIGHT_POSITIONS[LIGHT_COUNT] = vec3[](
104	    vec3( 3.8, 2.9,  3.8), // Canto Superior Direito (Frente)
105	    vec3(-3.8, 2.9,  3.8), // Canto Superior Esquerdo (Frente)
106	    vec3( 3.8, 2.9, -3.8), // Canto Superior Direito (Trás)
107	    vec3(-3.8, 2.9, -3.8)  // Canto Superior Esquerdo (Trás)
108	);
109	
110	// Cor das luzes (um branco levemente azulado, estilo laboratório)
111	const vec3 LIGHT_COLORS[LIGHT_COUNT] = vec3[](
112	    vec3(0.4, 0.6, 0.8),
113	    vec3(0.4, 0.6, 0.8),
114	    vec3(0.4, 0.6, 0.8),
115	    vec3(0.4, 0.6, 0.8)
116	);
