122	void main()
123	{
124	    // Obtemos a posição da câmera utilizando a inversa da matriz que define o
125	    // sistema de coordenadas da câmera.
126	    vec4 origin = vec4(0.0, 0.0, 0.0, 1.0);
127	    vec4 camera_position = inverse(view) * origin;
128	
129	    // O fragmento atual é coberto por um ponto que percente à superfície de um
130	    // dos objetos virtuais da cena. Este ponto, p, possui uma posição no
131	    // sistema de coordenadas global (World coordinates). Esta posição é obtida
132	    // através da interpolação, feita pelo rasterizador, da posição de cada
133	    // vértice.
134	    vec4 p = position_world;
135	
