137	    // normais de cada vértice.
138	    vec4 n = normalize(normal);
139	
140	    // Vetor que define o sentido da fonte de luz em relação ao ponto atual.
141	    vec4 l = normalize(vec4(1.0,1.0,0.0,0.0));
142	
143	    // Vetor que define o sentido da câmera em relação ao ponto atual.
144	    vec4 v = normalize(camera_position - p);
145	
146	    // Coordenadas de textura U e V
147	    float U = 0.0;
148	    float V = 0.0;
149	
150		// Coeficiente de refletância difusa
151		vec3 Kd0;
152	
153	    // Fator de refletância especular (o quanto o objeto brilha)
154	    float Ks_map = 0.0;
155	
156	    if ( object_id == SPHERE )
157	    {
158	        // PREENCHA AQUI as coordenadas de textura da esfera, computadas com
159	        // projeção esférica EM COORDENADAS DO MODELO. Utilize como referência
160	        // o slides 134-150 do documento Aula_20_Mapeamento_de_Texturas.pdf.
161	        // A esfera que define a projeção deve estar centrada na posição
162	        // "bbox_center" definida abaixo.
163	
164	        // Você deve utilizar:
165	        //   função 'length( )' : comprimento Euclidiano de um vetor
166	        //   função 'atan( , )' : arcotangente. Veja https://en.wikipedia.org/wiki/Atan2.
167	        //   função 'asin( )'   : seno inverso.
168	        //   constante M_PI
169	        //   variável position_model
170	
171	        vec4 bbox_center = (bbox_min + bbox_max) / 2.0;
172	        vec4 d = position_model - bbox_center;
173	
174	        float rho   = length(d);
175	        float theta = atan(d.x,d.z);
176	        float phi   = asin(d.y / rho);
177	
178	        U = (theta + M_PI) / 2.0 / M_PI;
179	        V = (phi + M_PI_2) / M_PI;
180	
181			// Obtemos a refletância difusa a partir da leitura da imagem TextureImage0
182			Kd0 = texture(TextureImage0, vec2(U,V)).rgb;
